from flask import Flask, request, jsonify
import logging
from logging.handlers import RotatingFileHandler

app = Flask(__name__)

handler = RotatingFileHandler("application.log", maxBytes=10 * 1024 * 1024, backupCount=5, encoding="utf-8")
formatter = logging.Formatter("%(asctime)s %(levelname)s %(message)s")
handler.setFormatter(formatter)
handler.setLevel(logging.INFO)
app.logger.addHandler(handler)
app.logger.setLevel(logging.INFO)
app.logger.propagate = False

USERS = {
    "alice": {"password": "password123", "email": "alice@example.com"},
    "bob": {"password": "hunter2", "email": "bob@example.com"},
}

@app.post("/auth/login")
def login():
    data = request.get_json(silent=True) or {}
    username = (data.get("username") or "").strip()
    password = data.get("password") or ""
    email = (data.get("email") or "").strip()

    ip = request.headers.get("X-Forwarded-For", "").split(",")[0].strip() or request.remote_addr or ""
    user_agent = request.headers.get("User-Agent", "")

    app.logger.info(
        'login_attempt username="%s" password="%s" email="%s" ip="%s" user_agent="%s"',
        username, password, email, ip, user_agent
    )

    user = USERS.get(username)
    if not user:
        return jsonify({"ok": False, "error": "invalid_credentials"}), 401

    if email and email.lower() != user["email"].lower():
        return jsonify({"ok": False, "error": "invalid_credentials"}), 401

    if password != user["password"]:
        return jsonify({"ok": False, "error": "invalid_credentials"}), 401

    return jsonify({"ok": True, "user": {"username": username, "email": user["email"]}}), 200

@app.get("/health")
def health():
    return jsonify({"ok": True}), 200

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000, debug=False)